@startuml
skinparam classAttributeIconSize 0
skinparam classFontColor black
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor black
skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeCBorderColor black
skinparam stereotypeCFontColor black
skinparam linetype ortho

class Princesa {
  + Princesa(string n);
  + Princesa(const Princesa& p)
  + void gritar()
}

class Villano {
  + Villano(string n);
  + Villano(const Villano& v)
  + void secuerstrar()
}

class Heroe {
  + Heroe(string n);
  + Heroe(const Heroe& h)
  + void salvar()
}

class SubClase {
  <<template>>
  + T* clone()
}

class Mundo {
  + string nombreMundo
  + Mundo(string nombreMundo)
}

class Personaje {
  <<abstract>>
  + string nombre;
  + string correo;
  + int telefono;
  + Mundo* mundo;
  + Personaje ();
  + Personaje(string nombre)
  + virtual Personaje* clone();
}

Princesa --|> SubClase
Villano --|> SubClase
Heroe --|> SubClase
SubClase ..|> Personaje
Mundo *-- Personaje

@enduml
